SELECT total_internet_subs
FROM subscriptions_by_year
WHERE state_id = 0 AND year = 2014;

SELECT AVG(avg_internet_usage) AS average_internet_usage
FROM internet_usage_trends
WHERE state_id = 0 AND year = 2015;

SELECT AVG(avg_internet_usage) AS avg_internet_usage
FROM internet_usage_trends
WHERE year = 2020;

SELECT total_internet_subs AS total_internet_subscriptions
  FROM subscriptions_by_year
  WHERE state_id = 0 AND year = 2014;

SELECT AVG(avg_internet_usage) AS avg_internet_usage_maharashtra
FROM internet_usage_trends
WHERE state_id = (SELECT state_id FROM states WHERE state_name = 'Maharashtra');

SELECT total_subscriptions, avg_download_speed
FROM internet_subscriptions
WHERE total_subscriptions > 10000000;
